const input = $input.first();
const body = input.json.body || {};
const topic = (typeof body === 'object' ? body.topic : '') || '';
const story = (typeof body === 'object' ? body.story : '') || '';
const audience = (typeof body === 'object' ? body.audience : '') || 'tech professionals';
const email = (typeof body === 'object' ? body.email : '') || 'petri.sandholm@gmail.com';

if (!topic || topic.trim().length < 3) {
  throw new Error('No topic. POST JSON with topic, story, and audience fields.');
}
if (!story || story.trim().length < 10) {
  throw new Error('No story. Add real context in the story field (2-3 sentences minimum).');
}

const fs = require('fs');
const pathLib = require('path');
const publishedDir = '/home/node/output/my-media-helper/published';
let posts = [];
let historyText = '';

try {
  const files = fs.readdirSync(publishedDir).filter(f => f.endsWith('.md')).sort();
  for (const file of files) {
    const content = fs.readFileSync(pathLib.join(publishedDir, file), 'utf-8').trim();
    if (content) posts.push({ file, content });
  }
  if (posts.length > 0) {
    historyText = posts.map((p, i) => '--- Post ' + (i + 1) + ' (' + p.file + ') ---\n' + p.content).join('\n\n');
  }
} catch (e) {
  historyText = '';
}

return [{ json: { topic: topic.trim(), story: story.trim(), audience: audience.trim(), email: email.trim(), posts, historyText } }];

const data = $('Load History').first().json;
const topic = data.topic;
const story = data.story;
const audience = data.audience;
const historyText = data.historyText;

const voiceSection = historyText
  ? 'Published posts by this author (study the voice and style):\n\n' + historyText + '\n\n'
  : '';

const prompt = voiceSection
  + 'Extract the key building blocks from this professional experience for a LinkedIn post.\n\n'
  + 'TOPIC: ' + topic + '\n'
  + 'EXPERIENCE/STORY: ' + story + '\n'
  + 'AUDIENCE: ' + audience + '\n\n'
  + 'Extract and return as JSON only:\n'
  + '{\n'
  + '  "hook": "one opening line under 10 words that creates curiosity or tension",\n'
  + '  "conflict": "the specific challenge or tension in 1-2 sentences with real details",\n'
  + '  "shift": "the realization or turning point in 1 sentence",\n'
  + '  "lesson": "the single key insight or takeaway in 1 sentence",\n'
  + '  "proof": "a specific detail, number, tool, or outcome that makes this credible",\n'
  + '  "question": "one question to end the post that invites comments"\n'
  + '}\n\n'
  + 'Use actual details from the story. Do not generalize. Output only the JSON.';

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 512,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { body, topic, story, audience, historyText } }];

const claudeResponse = $input.first().json.content[0].text;
const extractor = $('Story Extractor Build').first().json;
const historyText = extractor.historyText;
const topic = extractor.topic;
const audience = extractor.audience;
const story = extractor.story;

let elements;
try {
  const jsonMatch = claudeResponse.match(/\{[\s\S]+\}/);
  elements = JSON.parse(jsonMatch ? jsonMatch[0] : claudeResponse);
} catch (e) {
  elements = {
    hook: topic,
    conflict: story,
    shift: 'The perspective shifted after experiencing this directly.',
    lesson: 'The real lesson was in the details.',
    proof: story,
    question: 'What has been your experience with this?'
  };
}

const voiceSection = historyText
  ? 'Match this author voice exactly - study these published posts:\n\n' + historyText + '\n\n'
  : '';

const prompt = voiceSection
  + 'Write a LinkedIn post using the SLA framework: Story, Lesson, Application.\n\n'
  + 'Use these content elements:\n'
  + 'Hook (first line, under 10 words): ' + elements.hook + '\n'
  + 'Story/Conflict: ' + elements.conflict + '\n'
  + 'Shift: ' + elements.shift + '\n'
  + 'Lesson: ' + elements.lesson + '\n'
  + 'Proof: ' + elements.proof + '\n'
  + 'Closing question: ' + elements.question + '\n\n'
  + 'Structure:\n'
  + '1. Open with the hook\n'
  + '2. Tell the story with specific details (3-5 lines)\n'
  + '3. State the lesson (2-3 lines)\n'
  + '4. Show how to apply it (2-3 lines)\n'
  + '5. End with the closing question\n\n'
  + 'Hard requirements:\n'
  + '- 1300-1600 characters total\n'
  + '- Short paragraphs, 1-3 lines max, blank line between each\n'
  + '- No corporate words: leverage, utilize, delve, synergy\n'
  + '- No external links\n'
  + '- First person, do not start with the word I\n\n'
  + 'Output only the post text.';

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { body, elements, topic, historyText, audience } }];

const draft1 = $input.first().json.content[0].text;
const d1 = $('Draft 1 Build').first().json;
const elements = d1.elements;
const historyText = d1.historyText;
const topic = d1.topic;

const voiceSection = historyText
  ? 'Match this author voice exactly - study these published posts:\n\n' + historyText + '\n\n'
  : '';

const prompt = voiceSection
  + 'Write a LinkedIn post using the MRS framework: Mistake, Realization, Shift.\n\n'
  + 'Use these content elements:\n'
  + 'Hook (first line, bold admission or mistake, under 10 words): ' + elements.hook + '\n'
  + 'The mistake or wrong assumption: ' + elements.conflict + '\n'
  + 'The realization: ' + elements.shift + '\n'
  + 'What changed and why it matters: ' + elements.lesson + '\n'
  + 'Proof/evidence: ' + elements.proof + '\n'
  + 'Closing question: ' + elements.question + '\n\n'
  + 'Structure:\n'
  + '1. Open with a bold admission of a mistake or wrong assumption\n'
  + '2. Describe the mistake with specific details (2-3 lines)\n'
  + '3. The moment of realization (2-3 lines)\n'
  + '4. What shifted and why it matters (3-4 lines)\n'
  + '5. End with the closing question\n\n'
  + 'Hard requirements:\n'
  + '- 1300-1600 characters total\n'
  + '- Short paragraphs, 1-3 lines max, blank line between each\n'
  + '- No corporate words: leverage, utilize, delve, synergy\n'
  + '- No external links\n'
  + '- First person, do not start with the word I\n\n'
  + 'Output only the post text.';

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { body, draft1, elements, topic, historyText } }];

const draft2 = $input.first().json.content[0].text;
const d2 = $('Draft 2 Build').first().json;
const draft1 = d2.draft1;
const elements = d2.elements;
const historyText = d2.historyText;
const topic = d2.topic;

const voiceSection = historyText
  ? 'Match this author voice exactly - study these published posts:\n\n' + historyText + '\n\n'
  : '';

const prompt = voiceSection
  + 'Write a LinkedIn post that challenges a common assumption in this field.\n\n'
  + 'Topic: ' + topic + '\n'
  + 'Hook (bold contrarian statement under 10 words): ' + elements.hook + '\n'
  + 'Story/evidence: ' + elements.conflict + ' ' + elements.shift + '\n'
  + 'The contrarian insight: ' + elements.lesson + '\n'
  + 'Proof: ' + elements.proof + '\n'
  + 'Closing question: ' + elements.question + '\n\n'
  + 'Structure:\n'
  + '1. Bold opening statement that challenges conventional thinking\n'
  + '2. What most people believe or do (1-2 lines)\n'
  + '3. Your story or experience that disproves it (3-4 lines)\n'
  + '4. The real insight (2-3 lines)\n'
  + '5. End with a provocative question\n\n'
  + 'Hard requirements:\n'
  + '- 1300-1600 characters total\n'
  + '- Short paragraphs, 1-3 lines max, blank line between each\n'
  + '- No corporate words: leverage, utilize, delve, synergy\n'
  + '- No external links\n'
  + '- First person, do not start with the word I\n\n'
  + 'Output only the post text.';

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { body, draft1, draft2, elements, topic, historyText } }];

const draft3 = $input.first().json.content[0].text;
const d3 = $('Draft 3 Build').first().json;
const draft1 = d3.draft1;
const draft2 = d3.draft2;
const elements = d3.elements;
const topic = d3.topic;

const checklist = '1. Hook under 10 words (yes/no)\n'
  + '2. First 140 characters hooks before see more (yes/no)\n'
  + '3. Total length 1300-1600 characters (yes/no + actual count)\n'
  + '4. Paragraphs 1-3 lines max (yes/no)\n'
  + '5. No corporate buzzwords: leverage, utilize, delve, synergy (yes/no)\n'
  + '6. Personal story or specific proof present (yes/no)\n'
  + '7. Ends with a question (yes/no)\n'
  + '8. No external links (yes/no)\n'
  + '9. Reads like a human, not AI (yes/no)\n';

const prompt = 'Score these 3 LinkedIn post drafts against this exact checklist.\n\n'
  + 'CHECKLIST:\n' + checklist + '\n'
  + 'DRAFT 1 (SLA - Story, Lesson, Application):\n' + draft1 + '\n\n'
  + 'DRAFT 2 (MRS - Mistake, Realization, Shift):\n' + draft2 + '\n\n'
  + 'DRAFT 3 (Contrarian):\n' + draft3 + '\n\n'
  + 'For each draft output exactly:\n'
  + 'DRAFT [N]: [score]/10\n'
  + '[checklist item]: [yes/no]\n'
  + '(repeat for all 9 checklist items)\n'
  + 'IMPROVE: [2-3 specific improvements]\n\n'
  + 'End with:\n'
  + 'BEST: Draft [1/2/3] - [one sentence why]';

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1500,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { body, draft1, draft2, draft3, elements, topic } }];

const criticResponse = $input.first().json.content[0].text;
const cb = $('Critic Build').first().json;
const draft1 = cb.draft1;
const draft2 = cb.draft2;
const draft3 = cb.draft3;
const topic = cb.topic;

const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
const dateLabel = new Date().toISOString().split('T')[0];

const bestMatch = criticResponse.match(/BEST:\s*Draft\s*([123])/i);
const bestDraft = bestMatch ? bestMatch[1] : '1';

const s1 = (criticResponse.match(/DRAFT\s*1[^:]*:\s*(\d+)\/10/i) || [])[1] || '?';
const s2 = (criticResponse.match(/DRAFT\s*2[^:]*:\s*(\d+)\/10/i) || [])[1] || '?';
const s3 = (criticResponse.match(/DRAFT\s*3[^:]*:\s*(\d+)\/10/i) || [])[1] || '?';

const c1 = draft1.length;
const c2 = draft2.length;
const c3 = draft3.length;

const markdown = '# LinkedIn Post Drafts\n'
  + '**Topic:** ' + topic + '\n'
  + '**Date:** ' + dateLabel + '\n'
  + '**Recommended:** Draft ' + bestDraft + '\n\n'
  + '## Draft 1 - SLA (Story, Lesson, Application) - Score: ' + s1 + '/10\n\n'
  + draft1 + '\n\n'
  + '## Draft 2 - MRS (Mistake, Realization, Shift) - Score: ' + s2 + '/10\n\n'
  + draft2 + '\n\n'
  + '## Draft 3 - Contrarian - Score: ' + s3 + '/10\n\n'
  + draft3 + '\n\n'
  + '---\n\n## Critic Evaluation\n\n' + criticResponse + '\n';

const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const escPost = (s) => esc(s).replace(/\n/g, '<br>');
const escCritic = (s) => esc(s).replace(/\n/g, '<br>');

const scoreBadge = (score, isRec) => {
  const bg = isRec ? '#16a34a' : (parseInt(score) >= 7 ? '#2563eb' : '#6b7280');
  return '<span style="background-color:' + bg + '; color:#ffffff; font-family:Arial,sans-serif; font-size:11px; font-weight:bold; padding:2px 8px;">'
    + score + '/10' + (isRec ? ' - RECOMMENDED' : '') + '</span>';
};

const draftBlock = (num, framework, draft, score, chars) => {
  const isRec = String(num) === bestDraft;
  const border = isRec ? '2px solid #16a34a' : '1px solid #e5e7eb';
  return '<tr><td style="padding:0 0 20px 0;">'
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="border:' + border + ';">'
    + '<tr><td style="background-color:#f9fafb; padding:10px 18px; border-bottom:1px solid #e5e7eb;">'
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0"><tr>'
    + '<td><span style="font-family:Arial,sans-serif; font-size:13px; font-weight:bold; color:#111827;">Version ' + num + ': ' + framework + '</span>'
    + '<span style="font-family:Arial,sans-serif; font-size:11px; color:#9ca3af; margin-left:8px;">' + chars + ' chars</span></td>'
    + '<td align="right">' + scoreBadge(score, isRec) + '</td>'
    + '</tr></table>'
    + '</td></tr>'
    + '<tr><td style="padding:16px 18px; background-color:#ffffff; font-family:Arial,sans-serif; font-size:14px; color:#111827; line-height:1.8;">'
    + escPost(draft)
    + '</td></tr>'
    + '</table>'
    + '</td></tr>';
};

const html = '<!DOCTYPE html PUBLIC "-//W3C//DTD XHTML 1.0 Transitional//EN" "http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd">'
  + '<html xmlns="http://www.w3.org/1999/xhtml"><head>'
  + '<meta http-equiv="Content-Type" content="text/html; charset=utf-8">'
  + '<title>LinkedIn Drafts</title></head>'
  + '<body style="margin:0; padding:0; background-color:#f3f4f6;">'
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#f3f4f6;"><tr><td align="center" style="padding:24px 12px;">'
  + '<table width="620" cellpadding="0" cellspacing="0" border="0" style="max-width:620px; width:100%; background-color:#ffffff;">'
  + '<tr><td style="background-color:#0a66c2; padding:22px 28px;">'
  + '<div style="color:#ffffff; font-size:11px; font-family:Arial,sans-serif; opacity:0.8; margin-bottom:4px;">' + dateLabel + ' - 3 drafts</div>'
  + '<div style="color:#ffffff; font-size:19px; font-weight:bold; font-family:Arial,sans-serif;">' + esc(topic) + '</div>'
  + '</td></tr>'
  + '<tr><td style="background-color:#f0fdf4; padding:12px 28px; border-bottom:1px solid #e5e7eb;">'
  + '<span style="color:#16a34a; font-family:Arial,sans-serif; font-size:13px; font-weight:bold;">Recommended: Version ' + bestDraft + '</span>'
  + '<span style="color:#6b7280; font-family:Arial,sans-serif; font-size:13px;"> - all 3 versions below, pick one</span>'
  + '</td></tr>'
  + '<tr><td style="padding:22px 28px 4px 28px;">'
  + '<div style="font-size:11px; color:#6b7280; text-transform:uppercase; letter-spacing:1px; font-family:Arial,sans-serif; margin-bottom:16px;">3 versions - pick one to post</div>'
  + '<table width="100%" cellpadding="0" cellspacing="0" border="0">'
  + draftBlock(1, 'Story, Lesson, Application', draft1, s1, c1)
  + draftBlock(2, 'Mistake, Realization, Shift', draft2, s2, c2)
  + draftBlock(3, 'Contrarian', draft3, s3, c3)
  + '</table>'
  + '</td></tr>'
  + '<tr><td style="padding:0 28px 24px 28px;">'
  + '<div style="font-size:11px; color:#6b7280; text-transform:uppercase; letter-spacing:1px; font-family:Arial,sans-serif; margin-bottom:10px; margin-top:4px;">Critic evaluation</div>'
  + '<div style="background-color:#f9fafb; padding:14px 16px; font-family:Arial,sans-serif; font-size:12px; color:#374151; line-height:1.7; border:1px solid #e5e7eb;">'
  + escCritic(criticResponse)
  + '</div>'
  + '</td></tr>'
  + '<tr><td style="padding:12px 28px; background-color:#f9fafb; border-top:1px solid #e5e7eb; text-align:center;">'
  + '<div style="color:#9ca3af; font-size:11px; font-family:Arial,sans-serif;">my-media-helper</div>'
  + '</td></tr>'
  + '</table></td></tr></table></body></html>';

const email = $('Load History').first().json.email || 'petri.sandholm@gmail.com';

const buffer = Buffer.from(markdown, 'utf-8');
const binaryData = await this.helpers.prepareBinaryData(buffer, 'draft-' + timestamp + '.md', 'text/markdown');

return [{ json: { markdown, html, topic, timestamp, bestDraft, s1, s2, s3, email }, binary: { data: binaryData } }];
